package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.supplier.application.score.*;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.time.*;import java.util.List;
@RestController @RequestMapping("/api/supplier/v1")public class SupplierScoreController{private final SupplierScoreApplicationService service;private final CommandContextFactory contexts;public SupplierScoreController(SupplierScoreApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@GetMapping("/score-rules")public ApiResponse<List<ScoreViews.Rule>> rules(HttpServletRequest r){return ok(service.rules(),r);}@PostMapping("/score-rules")public ApiResponse<Long> createRule(@Valid @RequestBody Rule b,HttpServletRequest r,Authentication a){return ok(service.createRule(b.name(),b.dimensionCode(),b.metricCode(),b.weight(),b.targetValue(),b.direction(),b.effectiveFrom(),b.effectiveTo(),contexts.create(r,a)),r);}@PostMapping("/score-rules/{id}/publish")public ApiResponse<Void> publishRule(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){service.publishRule(id,b.version(),contexts.create(r,a));return ok(null,r);}@PostMapping("/score-rules/{id}/disable")public ApiResponse<Void> disableRule(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){service.disableRule(id,b.version(),contexts.create(r,a));return ok(null,r);}@PostMapping("/scores/calculate")public ApiResponse<ScoreViews.Result> calculate(@Valid @RequestBody Calculate b,HttpServletRequest r,Authentication a){return ok(service.calculate(b.supplierId(),YearMonth.parse(b.periodCode()),b.manualAdjustment(),b.adjustmentReason(),contexts.create(r,a)),r);}@PostMapping("/scores/{id}/publish")public ApiResponse<ScoreViews.Result> publish(@PathVariable long id,@Valid @RequestBody Version b,HttpServletRequest r,Authentication a){return ok(service.publish(id,b.version(),contexts.create(r,a)),r);}@GetMapping("/suppliers/{supplierId}/scores/{period}")public ApiResponse<ScoreViews.Result> result(@PathVariable long supplierId,@PathVariable String period,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ok(service.result(supplierId,period,scope(jwt)),r);}@GetMapping("/suppliers/{supplierId}/risks")public ApiResponse<List<ScoreViews.Risk>> risks(@PathVariable long supplierId,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ok(service.risks(supplierId,scope(jwt)),r);}@PostMapping("/risks/{id}/process")public ApiResponse<Void> process(@PathVariable long id,@Valid @RequestBody Process b,HttpServletRequest r,Authentication a){service.processRisk(id,b.version(),b.accepted(),contexts.create(r,a));return ok(null,r);}private <T>ApiResponse<T> ok(T v,HttpServletRequest r){return ApiResponse.success(v,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt j){Number n=j.hasClaim("supplier_id")?j.getClaim("supplier_id"):null;return n==null?null:n.longValue();}public record Rule(@NotBlank String name,@NotBlank String dimensionCode,@NotBlank String metricCode,@DecimalMin(value="0",inclusive=false)@DecimalMax("1")BigDecimal weight,@DecimalMin(value="0",inclusive=false)BigDecimal targetValue,@Min(1)@Max(2)int direction,@NotNull LocalDate effectiveFrom,LocalDate effectiveTo){}public record Version(@PositiveOrZero int version){}public record Calculate(@Positive long supplierId,@Pattern(regexp="\\d{4}-\\d{2}")String periodCode,BigDecimal manualAdjustment,String adjustmentReason){}public record Process(@PositiveOrZero int version,boolean accepted){} }
